#nullable enable // autogenerated    

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Models;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Level;
using Tools;

namespace MVZ2.GameContent.Buffs.Contraptions  
{  
    [BuffDefinition(VanillaBuffNames.Contraption.DrivenserTriggerBuff)]  
    public class DrivenserTriggerBuff : BuffDefinition  
    {  
        public DrivenserTriggerBuff(string nsp, string name) : base(nsp, name)  
        {  
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, VanillaModelKeys.ShockStaticParticles, VanillaModelID.ShockStaticParticles);  
        }  
        public override void PostAdd(Buff buff)  
        {  
            base.PostAdd(buff);  
            buff.SetProperty(PROP_TIMER, new FrameTimer(MAX_TIMEOUT));  
            buff.SetProperty(PROP_DAMAGE_TIMER, new FrameTimer(DAMAGE_INTERVAL));  
        }  
        public override void PostUpdate(Buff buff)  
        {  
            base.PostUpdate(buff);  
            var timer = buff.GetProperty<FrameTimer>(PROP_TIMER);  
            if (timer == null || timer.RunToExpired())  
            {  
                buff.Remove();  
                return;  
            }  
              
            // √Ņ30÷°‘ž≥…1Ķ„…ňļ¶  
            var damageTimer = buff.GetProperty<FrameTimer>(PROP_DAMAGE_TIMER);  
            if (damageTimer != null && damageTimer.RunToExpired())  
            {  
                var entity = buff.GetEntity();  
                if (entity != null && entity.Health > 0)  
                {  
                    entity.TakeDamage(1, new DamageEffectList(VanillaDamageEffects.MUTE, VanillaDamageEffects.NO_DAMAGE_BLINK), entity);  
                }  
                damageTimer.Reset();  
            }  
        }  
        public const int MAX_TIMEOUT = 900; // 30√Ž (30 * 30÷°)    
        public const int DAMAGE_INTERVAL = 30; // …ňļ¶ľšłŰ£®30÷° = 1√Ž£©  
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("Timer");  
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_DAMAGE_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("DamageTimer");  
    }  
}